css_template:
#{{ID}} .lt-container {
padding: 0;
font-family: '{{FONT_FAMILY}}', sans-serif;
line-height: {{LINE_HEIGHT}};
}
#{{ID}} .plate {
background: {{PRIMARY_BG}};
padding: 20px 40px;
border-left: 10px solid {{SECONDARY_COLOR}};
color: white;
display: inline-block;
box-shadow: {{BOX_SHADOW}};
opacity: 0;
transform: {{ANIMATION_IN_TRANSFORM}};
transition: all {{ANIMATION_DURATION}}s {{ANIMATION_EASE}};
}
#{{ID}} .title {
margin: 0;
font-size: {{TITLE_SIZE}}px;
font-weight: {{TITLE_WEIGHT}};
text-transform: {{TITLE_TRANSFORM}};
letter-spacing: -1px;
}

js_template:
(() => { const root = document.getElementById("{{ID}}"); const container = root.querySelector('.plate'); root.__slt_show = () => { const tl = GSAPFX.standardIn(container, {{{ANIMATION_IN_JSON}}}); const textTl = GSAPFX.applyTextEffect(root, {{{TEXT_ANIM_JSON}}}); if (textTl) {
            if ({{{TEXT_ANIM_SYNC}}}) {
                tl.add(textTl, ">-0.1");
            } else {
                tl.add(textTl, 0);
            }
        } return tl; }; root.__slt_hide = () => { const textTl = GSAPFX.applyTextOutEffect(root, {{{TEXT_ANIM_OUT_JSON}}}); const tl = GSAPFX.standardOut(container, {{{ANIMATION_OUT_JSON}}}); if (textTl) {
            if ({{{TEXT_ANIM_OUT_SYNC}}}) {
                const combined = gsap.timeline();
                combined.add(textTl);
                combined.add(tl, ">-0.1");
                return combined;
            } else {
                tl.add(textTl, 0);
            }
        } return tl; }; })();
